        question(10, "How many regulation periods are in ice hockey?", ["2", "3", "4", "Unlimited"], 1, "A regulation ice hockey game has three periods."),
        question(11, "What does both teams to score — yes require?", ["Either team to win", "Both teams to score at least once", "An own goal", "No goals"], 1, "Each team must score one or more goals."),
        question(12, "Which country is considered the birthplace of the Olympic Games?", ["Italy", "England", "Greece", "France"], 2, "The ancient Olympic Games originated in Greece."),
        question(13, "What is cash out?", ["A bookmaker bankruptcy", "Early settlement before an event ends", "A bank withdrawal", "A loan"], 1, "Cash out settles a bet before the underlying event is complete."),
        question(14, "How long is a standard professional boxing round?", ["2 minutes", "3 minutes", "5 minutes", "10 minutes"], 1, "Standard professional rounds are three minutes."),
