        question(19, "Which competition awards the European Champion Clubs' Cup?", ["Europa League", "UEFA Champions League", "Copa Libertadores", "FIFA World Cup"], 1, "The trophy is awarded to the UEFA Champions League winner."),
        question(20, "What is flat staking?", ["Doubling after a loss", "Backing an underdog", "Using a fixed stake or percentage", "Buying predictions"], 2, "Flat staking keeps the amount or bankroll percentage consistent.")
    ]

    private static func question(
        _ id: Int,
        _ prompt: String,
        _ answers: [String],
        _ correctIndex: Int,
        _ explanation: String
